1	const mongoose = require('mongoose');
2	const Claim = require('../models/Claim');
3	const ClaimDecision = require('../models/ClaimDecision');
4	const LimitLedger = require('../models/LimitLedger');
5	const { adjudicateClaim } = require('./adjudication.service');
6	const limitService = require('./limit.service');
7	
8	// Valid state transitions — all other moves are rejected.
9	const TRANSITIONS = {
10	  SUBMITTED: ['UNDER_REVIEW'],
11	  UNDER_REVIEW: ['APPROVED', 'PARTIALLY_APPROVED', 'DENIED'],
12	  APPROVED: ['PAID', 'DISPUTED'],
13	  PARTIALLY_APPROVED: ['PAID', 'DISPUTED'],
14	  DENIED: ['DISPUTED'],
15	  PAID: [],
16	  DISPUTED: ['UNDER_REVIEW']
17	};
18	
19	function assertTransition(from, to) {
20	  if (!TRANSITIONS[from]?.includes(to)) {
21	    throw Object.assign(new Error(`Invalid transition: ${from} → ${to}`), { statusCode: 422 });
22	  }
23	}
24	
25	async function submitClaim(claimData) {
26	  const claim = new Claim({ ...claimData, status: 'SUBMITTED' });
27	  await claim.save();
28	  return claim;
29	}
30	
31	// Move to UNDER_REVIEW and run adjudication.
32	async function reviewClaim(claimId) {
33	  const claim = await Claim.findById(claimId);
34	  if (!claim) throw Object.assign(new Error('Claim not found'), { statusCode: 404 });
35	  assertTransition(claim.status, 'UNDER_REVIEW');
36	
37	  claim.status = 'UNDER_REVIEW';
